/** Reverse lookup: state → its zone. */
export const ZONE_OF_STATE: Record<string, string> = {};
Object.keys(ZONE_STATES).forEach((z) =>
  ZONE_STATES[z].forEach((st) => {
    ZONE_OF_STATE[st] = z;
  })
);

/** Distinct donor / programme list, derived from the footprint. */
export const ALL_DONORS: string[] = Array.from(
  new Set(Object.values(STATE_DONORS).flat())
).sort();
